"""
MKT Christ Commentary — Isaiah 43 (28 verses — Fear Not / New Exodus)
Run: python3 scripts/zc-christ-isaiah-43.py
Key decisions:
- v1: "Fear not, I have redeemed you, called you by name, you are mine" —
  the pastoral heart of Second Isaiah; John 10:3 (the shepherd calls his
  sheep by name); 1 Pet 1:18-19 (redeemed by Christ's blood, not silver/gold)
- v2: Water and fire trials — NT baptism theology (death-and-resurrection
  pattern); Rom 8:28 (all things work together for good)
- v3: "I give Egypt as your ransom" — substitutionary exchange pattern;
  Mark 10:45 (Son of Man gives his life as a ransom for many)
- vv10-13: "You are my witnesses... I am He" — John 8:58 ("Before Abraham
  was, I am"); Acts 1:8 ("you will be my witnesses"); double "I am He"
  formula = divine self-identification
- vv16-21: New exodus through the sea / desert — 1 Cor 10:1-4 (baptized
  into Moses; the rock was Christ); "do not remember the former things"
  = the new covenant surpasses the old exodus
- v25: "I, I am He who blots out your transgressions for my own sake" —
  the ultimate grounding of forgiveness in divine character, fulfilled
  in the cross where justice and mercy meet (Rom 3:25-26)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If isaiah.json schema changes, update merge_comm and ISAIAH dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   isaiah.json')); print('Isa 43 v1:',d.get('43',{}).get('1','MISSING')[:80])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


ISAIAH = {
    "43": {
        "1": "<p>\"But now thus says the LORD, he who created you, O Jacob, he who formed you, O Israel: 'Fear not, for I have redeemed you; I have called you by name, you are mine'\" — the pivot from judgment (ch. 42's diagnosis of blind Israel) to promise: \"But now\" (<em>wĕʿattāh</em>) is the hinge. The same creator who judges calls by name and redeems. John 10:3: \"The gatekeeper opens the gate for him, and the sheep listen to his voice. He calls his own sheep by name and leads them out.\" 1 Peter 1:18-19: \"For you know that it was not with perishable things such as silver or gold that you were redeemed from the empty way of life handed down to you from your ancestors, but with the precious blood of Christ, a lamb without blemish or defect.\" The \"I have redeemed you\" of Isaiah 43:1 is the promissory note; 1 Peter 1:18-19 is the payment. The \"called you by name\" is fulfilled in John 10:3 and individually in John 20:16 (\"Jesus said to her, 'Mary'\" — the first resurrection appearance is a name-calling).</p>",
        "2": "<p>\"When you pass through the waters, I will be with you; and through the rivers, they shall not overwhelm you; when you walk through fire you shall not be burned, and the flame shall not consume you\" — the promise of divine presence through trials: water and fire are the two fundamental threat-elements. Romans 8:28: \"And we know that in all things God works for the good of those who love him, who have been called according to his purpose.\" Romans 8:35-37: \"Who shall separate us from the love of Christ? Shall trouble or hardship or persecution or famine or nakedness or danger or sword?... No, in all these things we are more than conquerors through him who loved us.\" The waters-and-fire of Isaiah 43:2 are Paul's \"trouble or hardship or persecution\" — in all of them the divine presence remains. The three young men in Daniel 3:24-25 literally walk through fire and are joined by \"one like a son of God\" — Isaiah 43:2 performed in narrative, pointing to the one who is present in every fiery trial.</p>",
        "3": "<p>\"For I am the LORD your God, the Holy One of Israel, your Savior. I give Egypt as your ransom, Cush and Seba in exchange for you\" — the substitutionary exchange: Egypt, Cush, Seba given as ransom (<em>kōper</em>) for Israel. The <em>kōper</em> (ransom/atoning price) language establishes the pattern that reaches its fulfillment in Christ. Mark 10:45: \"For even the Son of Man did not come to be served, but to serve, and to give his life as a ransom (<em>lytron</em>) for many.\" 1 Timothy 2:5-6: \"For there is one God and one mediator between God and mankind, the man Christ Jesus, who gave himself as a ransom for all people.\" The ransom of Isaiah 43:3 (nations substituted for Israel) becomes the ultimate ransom of the NT: not nations for Israel but the Savior himself for all who are his. The pattern — someone else in your place — is the pattern of the cross.</p>",
        "4": "<p>\"Because you are precious in my eyes, and honored, and I love you, I give men in return for you, peoples in exchange for your life\" — the love that drives the ransom: the exchange flows from the divine love for the covenant people. John 3:16: \"For God so loved the world that he gave his one and only Son, that whoever believes in him shall not perish but have eternal life.\" Romans 5:8: \"But God demonstrates his own love for us in this: While we were still sinners, Christ died for us.\" The \"precious in my eyes... I love you\" of Isaiah 43:4 is the foundation of the Johannine \"God so loved the world\" — the same love-driven substitutionary exchange. The nations given in exchange for Israel become in the NT the Son given in exchange for the world: the scale of the love increases from the particular (Israel) to the universal (world) in Christ's cross.</p>",
        "5": "<p>\"Fear not, for I am with you; I will bring your offspring from the east and from the west I will gather you\" — the second \"fear not\" in four verses: divine presence as the grounds of fearlessness. The gathering of scattered Israel from all directions points to the eschatological regathering. Matthew 24:31: \"And he will send his angels with a loud trumpet call, and they will gather his elect from the four winds, from one end of the heavens to the other.\" Matthew 28:20: \"And surely I am with you always, to the very end of the age.\" The \"I am with you\" of Isaiah 43:5 is the Immanuel promise (7:14: \"God with us\") extended — and fulfilled in the incarnation (the Word who dwells among us, John 1:14) and the Spirit (John 14:16-17: another Advocate, who will be with you forever). The gathering from east and west is the universal mission of Matthew 28.</p>",
        "6": "<p>\"I will say to the north, Give up, and to the south, Do not withhold; bring my sons from afar and my daughters from the end of the earth\" — the command to the compass-points: YHWH commands the regions to release his children. The \"sons\" and \"daughters\" language is covenant-family language for the people of God. Galatians 3:28-29: \"There is neither Jew nor Gentile, neither slave nor free, nor is there male and female, for you are all one in Christ Jesus. If you belong to Christ, then you are Abraham's seed, and heirs according to the promise.\" Romans 8:14-15: \"For those who are led by the Spirit of God are the children of God... the Spirit you received brought about your adoption to sonship.\" The sons and daughters gathered from the ends of the earth in Isaiah 43:6 are the adopted children of God in Christ — brought from every direction into the family of God through the Spirit of adoption.</p>",
        "7": "<p>\"Everyone who is called by my name, whom I created for my glory, whom I formed and made\" — the definition of those gathered: created and formed for divine glory. The creation-language (created, formed, made — three verbs echoing Gen 1-2) ties the gathering to the original purpose of humanity: bearing the image of God, reflecting his glory. 1 Corinthians 10:31: \"So whether you eat or drink or whatever you do, do it all for the glory of God.\" Romans 11:36: \"For from him and through him and for him are all things. To him be the glory forever! Amen.\" Ephesians 1:5-6: \"he predestined us for adoption to sonship through Jesus Christ, in accordance with his pleasure and will — to the praise of his glorious grace.\" The creation-for-glory of Isaiah 43:7 is the election-for-praise of Ephesians 1 — both root the covenant community in the divine purpose that precedes history and ends in the glorification of God through his people.</p>",
        "8": "<p>\"Bring out the people who are blind, yet have eyes, and who are deaf, yet have ears\" — the paradox from Isaiah 42:18 continues: the blind-yet-eyed, deaf-yet-eared. Both the covenant people and the nations are summoned to the cosmic trial where YHWH will prove his uniqueness. Acts 26:17-18: Paul's commission from the risen Christ: \"I am sending you to them to open their eyes and turn them from darkness to light, and from the power of Satan to God, so that they may receive forgiveness of sins and a place among those who are sanctified by faith in me.\" The blind-yet-eyed people of Isaiah 43:8 are the people whom Paul is sent to open — the Gentiles who have natural sight but lack spiritual sight until the gospel opens their eyes. Ephesians 1:18: \"I pray that the eyes of your heart may be enlightened.\"</p>",
        "9": "<p>\"All the nations gather together, and the peoples assemble. Who among them can declare this, and show us the former things? Let them bring their witnesses to prove them right, and let them hear and say, It is true\" — the cosmic trial: YHWH summons all nations to the courtroom where the question is: which god predicted the course of history? The challenge is aimed at the idol-gods of the nations. 1 Corinthians 8:5-6: \"For even if there are so-called gods, whether in heaven or on earth (as indeed there are many 'gods' and many 'lords'), yet for us there is but one God, the Father... and there is but one Lord, Jesus Christ, through whom all things came and through whom we live.\" The cosmic trial of Isaiah 43:9 is the trial that Christ wins by his resurrection: no other claimant to deity has risen from the dead and thus demonstrated predictive knowledge and sovereign control over history. The witnesses who say \"It is true\" in Isaiah 43:9 are the apostolic witnesses of Acts 1:22 who saw the risen Christ.</p>",
        "10": "<p>\"'You are my witnesses,' declares the LORD, 'and my servant whom I have chosen, that you may know and believe me and understand that I am he. Before me no god was formed, nor shall there be any after me'\" — the witness commission and the divine self-declaration. Acts 1:8: \"But you will receive power when the Holy Spirit comes on you; and you will be my witnesses in Jerusalem, and in all Judea and Samaria, and to the ends of the earth.\" The \"my witnesses\" of Isaiah 43:10 is the source text for the Acts 1:8 commission. John 8:24: \"I told you that you would die in your sins; if you do not believe that I am he, you will indeed die in your sins.\" The \"I am he\" (<em>ʾānî hûʾ</em>) is the divine self-identification that Jesus claims in John 8:24, 28, 58 (\"Before Abraham was, I am\"). The witness-commission and the I-AM claim belong together: the witnesses testify to the I AM who is Jesus Christ.</p>",
        "11": "<p>\"I, I am the LORD, and besides me there is no savior\" — the exclusive-savior claim: no other entity in the cosmos can save. The double \"I\" (<em>ʾānôḵî ʾānôḵî YHWH</em>) is emphatic. Acts 4:12: \"Salvation is found in no one else, for there is no other name under heaven given to mankind by which we must be saved.\" John 14:6: \"I am the way and the truth and the life. No one comes to the Father except through me.\" The Isaiah 43:11 exclusive-savior claim is the ground of the Acts 4:12 exclusive-name claim: YHWH declared \"no savior besides me\"; Peter declares \"no name... by which we must be saved\" — and the name is Jesus, who is YHWH the Savior (the name Jesus/Yeshua = YHWH saves). The claim is not modified but fulfilled in Christ: YHWH-the-only-Savior saves through the human person of Jesus.</p>",
        "12": "<p>\"I declared and saved and proclaimed, when there was no strange god among you; and you are my witnesses,' declares the LORD, 'and I am God'\" — the summary of YHWH's exclusive redemptive track record: he declared, saved, proclaimed — without any help from other gods. The witnesses are the covenant people who observed YHWH's sole action in every redemption. Hebrews 12:2: \"fixing our eyes on Jesus, the pioneer and perfecter of faith.\" 1 John 5:20: \"We know also that the Son of God has come and has given us understanding, so that we may know him who is true. And we are in him who is true by being in his Son Jesus Christ. He is the true God and eternal life.\" The exclusive-God of Isaiah 43:12 is the \"true God\" of 1 John 5:20, identified as Jesus Christ — YHWH's exclusive declarations and salvations find their definitive expression in the incarnation, cross, and resurrection of the Son.</p>",
        "13": "<p>\"Also henceforth I am he; there is none who can deliver from my hand; I work, and who can turn it back?\" — the irresistible divine sovereignty: no one can deliver from YHWH's hand, and no one can reverse his work. John 10:29: \"My Father, who has given them to me, is greater than all; no one can snatch them out of my Father's hand.\" Romans 8:31: \"If God is for us, who can be against us?\" 8:38-39: \"neither death nor life, neither angels nor demons, neither the present nor the future, nor any powers, neither height nor depth, nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord.\" The \"none can deliver from my hand\" of Isaiah 43:13 becomes the security of the believer in Romans 8 and John 10 — the Father's hand that no one can pry open is the hand in which the believer rests through Christ.</p>",
        "14": "<p>\"Thus says the LORD, your Redeemer, the Holy One of Israel: 'For your sake I send to Babylon and bring them all down as fugitives, even the Chaldeans, in the ships in which they rejoice'\" — YHWH as Redeemer who will bring Babylon down: the empire that carried Israel into exile will be undone for Israel's sake. Revelation 18:2: \"Fallen! Fallen is Babylon the Great!\" Revelation 18:20: \"Rejoice over her, you people of God!\" The fall of Babylon in Isaiah 43:14 is the type of Revelation's great Babylon — every empire that holds the people of God captive is under the same divine judgment. The ships of Chaldean pride in Isaiah 43:14 become the mourned ships of the merchants in Revelation 18:17-19. Christ is the Redeemer who accomplishes the exodus from every Babylon — not by political reversal but by the cross, resurrection, and ultimate return.</p>",
        "15": "<p>\"I am the LORD, your Holy One, the Creator of Israel, your King\" — the fourfold divine identity: Holy One, Creator, King, LORD. The royal-creator claim frames the coming salvation as both cosmic and political — YHWH rules over both creation and the covenant people. 1 Timothy 6:15: \"God, the blessed and only Ruler, the King of kings and Lord of lords.\" Revelation 19:16: \"On his robe and on his thigh he has this name written: King of Kings and Lord of Lords.\" The \"your King\" of Isaiah 43:15 finds its final expression in the returning Christ of Revelation 19 — the Creator who is also King has entered his creation as the suffering servant and will return as the sovereign King. John 18:37: \"'You are a king, then!' said Pilate. Jesus answered, 'You say that I am a king. In fact, the reason I was born and came into the world is to testify to the truth.'\"</p>",
        "16": "<p>\"Thus says the LORD, who makes a way in the sea, a path in the mighty waters\" — the new exodus begins with the memory of the old: YHWH who made a path through the Red Sea (Exod 14) is about to do something greater. 1 Corinthians 10:1-4: \"For I do not want you to be ignorant of the fact, brothers and sisters, that our ancestors were all under the cloud and that they all passed through the sea. They were all baptized into Moses in the cloud and in the sea... and drank from the spiritual rock that accompanied them, and that rock was Christ.\" Paul's reading of the Exodus makes Christ the presence in the original events — the one who made the way through the sea was the preincarnate Christ, whose cross then becomes the ultimate sea-crossing through death to resurrection. Baptism is the Christian participation in this sea-crossing (Rom 6:3-4).</p>",
        "17": "<p>\"Who brings out chariot and horse, army and warrior; they lie down, they cannot rise, they are extinguished, quenched like a wick\" — the Pharaoh's army quenched like a wick at the Exodus — the very image of extinguished power. The connection to Isaiah 42:3 (the smoldering wick the Servant will not quench) is deliberate: YHWH does not quench the faintly burning wick of the vulnerable (42:3) but does quench the militarized powers that oppose his people (43:17). Revelation 19:20-21: \"But the beast was captured, and with it the false prophet who had performed the signs on its behalf... The rest were killed with the sword coming out of the mouth of the rider on the horse.\" The Pharaoh's army extinguished at the Exodus is the type of the beast's armies destroyed at the parousia — every armed force that opposes the people of God is met by the same divine extinguishing.</p>",
        "18": "<p>\"Remember not the former things, nor consider the things of old\" — the astonishing command: forget the Exodus. After evoking the Exodus as ground for trust (vv16-17), YHWH commands the community not to dwell on it — because something greater is coming. 2 Corinthians 5:17: \"Therefore, if anyone is in Christ, the new creation has come: The old has gone, the new is here!\" Philippians 3:13-14: \"forgetting what is behind and straining toward what is ahead, I press on toward the goal to win the prize for which God has called me heavenward in Christ Jesus.\" The \"remember not the former things\" of Isaiah 43:18 is Paul's \"forgetting what is behind\" — not denial of the past but re-orientation toward the surpassing glory of the new thing in Christ. The Exodus was the paradigm of salvation for centuries; the cross-resurrection is the new paradigm that makes the Exodus its type rather than its antitype.</p>",
        "19": "<p>\"Behold, I am doing a new thing; now it springs forth, do you not perceive it? I will make a way in the wilderness and rivers in the desert\" — the new creation: a way in the wilderness, rivers in the desert — the reversal of what wilderness means. Revelation 21:5: \"He who was seated on the throne said, 'I am making everything new!'\" John 4:10-14: Jesus and the Samaritan woman — \"whoever drinks the water I give them will never thirst. Indeed, the water I give them will become in them a spring of water welling up to eternal life.\" Revelation 22:17: \"Let whoever is thirsty come; and let whoever wishes take the free gift of the water of life.\" The rivers in the desert of Isaiah 43:19 are the living water that Christ gives — the Spirit who flows from the risen Christ (John 7:38-39: \"Rivers of living water will flow from within them... By this he meant the Spirit\"). The new thing that \"springs forth\" is the Spirit-age inaugurated by Christ's resurrection.</p>",
        "20": "<p>\"The wild beasts will honor me, the jackals and the ostriches, for I give water in the wilderness, rivers in the desert, to give drink to my chosen people\" — the transformed creation honoring YHWH: even the desert animals participate in the cosmic praise triggered by the new creation. Romans 8:19-21: \"For the creation waits in eager expectation for the children of God to be revealed. For the creation was subjected to frustration... in hope that the creation itself will be liberated from its bondage to decay and brought into the freedom and glory of the children of God.\" The wild beasts honoring YHWH in Isaiah 43:20 anticipate the liberated creation of Romans 8 — the wilderness transformed by the Spirit's rivers is the creation set free from decay through the new creation in Christ. Revelation 5:13: \"Then I heard every creature in heaven and on earth and under the earth and on the sea, and all that is in them, singing: 'To him who sits on the throne and to the Lamb be praise and honor and glory and power, for ever and ever!'\"</p>",
        "21": "<p>\"The people whom I formed for myself that they might declare my praise\" — the purpose of the gathered people: to declare divine praise (<em>tĕhillāh</em>). The community of the redeemed is a praise-community. 1 Peter 2:9: \"But you are a chosen people, a royal priesthood, a holy nation, God's special possession, that you may declare the praises of him who called you out of darkness into his wonderful light.\" Peter directly echoes the Isaiah 43:21 language — the people formed for praise are the church, formed by Christ's blood, existing to declare the praises of the one who called them. Ephesians 1:12: \"in order that we, who were the first to put our hope in Christ, might be for the praise of his glory.\" The church's existence — formed, gathered, and sustained by Christ — is structured around the declaration of praise that Isaiah 43:21 anticipates.</p>",
        "22": "<p>\"Yet you did not call upon me, O Jacob; but you have been weary of me, O Israel!\" — the reversal: YHWH formed them for praise (v21) but they were weary of him. The covenant community that exists to worship has grown tired of the one it was made to glorify. Hebrews 12:1-2: \"let us run with perseverance the race marked out for us, fixing our eyes on Jesus, the pioneer and perfecter of faith.\" Hebrews 10:25: \"not giving up meeting together, as some are in the habit of doing, but encouraging one another.\" The weariness of Israel in Isaiah 43:22 is the weariness that Hebrews repeatedly warns against — the drift from gathered worship that comes from fixing eyes on circumstances rather than on Christ. Revelation 2:4: \"Yet I hold this against you: You have forsaken the love you had at first.\" The Ephesian church's loss of first love is the Isaianic weariness re-enacted in the NT community.</p>",
        "23": "<p>\"You have not brought me your sheep for burnt offerings, or honored me with your sacrifices. I have not burdened you with offerings, or wearied you with frankincense\" — the critique of failed worship: Israel has not brought the covenant offerings, yet YHWH has not been unreasonably demanding. Micah 6:6-8: \"With what shall I come before the LORD and bow down before the exalted God?... He has shown you, O mortal, what is good. And what does the LORD require of you? To act justly and to love mercy and to walk humbly with your God.\" Hebrews 10:5-7: \"Therefore, when Christ came into the world, he said: 'Sacrifice and offering you did not desire, but a body you prepared for me; with burnt offerings and sin offerings you were not pleased. Then I said, \"Here I am — it is written about me in the scroll — I have come to do your will, my God.\"'\" The failed sacrifices of Isaiah 43:23 are answered by the one true sacrifice — Christ who does what Israel could not, bringing the perfect offering.</p>",
        "24": "<p>\"You have not bought me sweet cane with money, or satisfied me with the fat of your sacrifices. But you have burdened me with your sins; you have wearied me with your iniquities\" — the reversal: instead of Israel being burdened by YHWH's requirements (v23), YHWH has been burdened by Israel's sins. The burden has been running in the wrong direction. Isaiah 53:4: \"Surely he took up our pain and bore our suffering.\" Matthew 11:28-30: \"Come to me, all you who are weary and burdened, and I will give you rest. Take my yoke upon you and learn from me, for I am gentle and humble in heart, and you will find rest for your souls.\" The burden of sins that Israel placed on YHWH in Isaiah 43:24 is the burden that Christ takes in Isaiah 53:4 and Matthew 11:28 — the weight of human transgression that \"wearies\" the divine holiness is transferred to the Servant who bears it in place of the guilty. The cross is the resolution of Isaiah 43:24's burden.</p>",
        "25": "<p>\"I, I am he who blots out your transgressions for my own sake, and I will not remember your sins\" — the double-I declaration of forgiveness: <em>ʾānôḵî ʾānôḵî hûʾ</em> (I, I am He). The forgiveness is grounded not in Israel's merit but in divine character: \"for my own sake.\" Romans 3:25-26: \"God presented Christ as a sacrifice of atonement, through the shedding of his blood — to be received by faith. He did this to demonstrate his righteousness... so as to be just and the one who justifies those who have faith in Jesus.\" Hebrews 8:12: \"For I will forgive their wickedness and will remember their sins no more.\" (Quoting Jer 31:34 — the new covenant.) The \"I will not remember your sins\" of Isaiah 43:25 is the new covenant promise, and the \"for my own sake\" is the divine motivation that finds its explanation in the cross: God blots out transgressions for the sake of his own righteousness, which required both punishment (in Christ) and forgiveness (of the penitent) — both happen at the cross.</p>",
        "26": "<p>\"Put me in remembrance; let us argue together; set forth your case, that you may be proved right\" — the divine invitation to legal argument: YHWH invites Israel to make its case before him. The courtroom-dialogue is a pastoral device — YHWH knows Israel has no case (v27-28) but invites the argument so the reality can be acknowledged. Romans 3:19-20: \"Now we know that whatever the law says, it says to those who are under the law, so that every mouth may be silenced and the whole world held accountable to God. Therefore no one will be declared righteous in God's sight by the works of the law.\" Paul's \"every mouth silenced\" is the outcome of the Isaiah 43:26 invitation — when the case is laid out, no human can be proved right. The legal verdict of condemnation (v27-28) leads to the unexpected gift: the divine forgiveness of v25 (given before the trial rather than waiting for its outcome).</p>",
        "27": "<p>\"Your first father sinned, and your mediators transgressed against me\" — the historical root of Israel's guilt: Adam (\"your first father\") and the priestly/prophetic mediators who transmitted sin rather than prevented it. Romans 5:12: \"Therefore, just as sin entered the world through one man, and death through sin, and in this way death came to all people, because all sinned.\" Hebrews 9:15: \"For this reason Christ is the mediator of a new covenant, that those who are called may receive the promised eternal inheritance — now that he has died as a ransom to set them free from the sins committed under the first covenant.\" The first father's sin (Is 43:27) is Romans 5's Adam; the failed mediators are replaced by the one true Mediator (1 Tim 2:5: \"there is one God and one mediator between God and mankind, the man Christ Jesus\"). The failure-chain from Adam through the priestly mediators is broken by Christ, the second Adam and true High Priest.</p>",
        "28": "<p>\"Therefore I will profane the princes of the sanctuary, and deliver Jacob to utter destruction and Israel to reviling\" — the judgment that follows from vv27's diagnosis: the holy offices (princes of the sanctuary) are profaned, the people are given to destruction. The exile is YHWH's own act of judgment, not Babylon's triumph. But the chapter began with redemption (vv1-7) and the middle declared forgiveness (v25) — the judgment of v28 is not the final word. Isaiah 53:5-6: \"But he was pierced for our transgressions, he was crushed for our iniquities; the punishment that brought us peace was on him... and the LORD has laid on him the iniquity of us all.\" The \"utter destruction\" of Isaiah 43:28 that Israel deserved is the destruction that falls on the Servant of Isaiah 53 — the judgment that should have destroyed Jacob falls on the one who represents Jacob, so that the restoration of vv1-7 and the forgiveness of v25 can be enjoyed. Chapter 43 moves from promise (vv1-7) through trial (vv8-28) and back to promise (v25) — the structure of grace that brackets judgment.</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "isaiah")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, ISAIAH)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "isaiah", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("1", "redeemed"), ("10", "witnesses"), ("19", "new"), ("25", "blots")]:
        entry = existing.get("43", {}).get(v, "MISSING")
        print(f"  Isa 43:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    ch = existing.get("43", {})
    missing = [str(i) for i in range(1, 29) if str(i) not in ch]
    print(f"  Missing verses: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
